export interface ObdDashboardProps {
  series: ObdDataPoint[];
  metrics: Record<string, ObdMetric>;
}

interface MetricCardProps {
  name: string;
  value: string | number;
  unit: string;
  isAvailable: boolean;
  isSelected: boolean;
