  '10': { name: '흡입 공기량 (MAF Rate)', unit: 'g/s', formula: (v) => (v[0] * 256 + v[1]) / 100 },
  '11': { name: '스로틀 위치 (Throttle Position)', unit: '%', formula: (v) => (v[0] * 100) / 255 },
