import { LogEntry, LogCategory, SessionMetadata, ParsedData, ConnectionDiagnosis, LifecycleEvent } from '../types';
import { parseObdLine, aggregateMetrics } from './obdParser';

// 정규식 패턴 (가이드 기반)
const REGEX_LOG_LINE = /^\[(\d{4}-\d{2}-\d{2}\s\d{2}:\d{2}:\d{2}[:\.]\d{3})\]\/\/([\s\S]*)/;
const SECTION_HEADER = /^={3,}\s*(.*?)\s*={3,}/;
const KEY_VALUE_PAIR = /^([^:]+?)\s*:\s*(.*)/;

const getDateFromFileName = (fileName: string): Date => {
  try {
    const match = fileName.match(/(\d{4})-(\d{2})-(\d{2})/);
    if (match) {
      return new Date(parseInt(match[1]), parseInt(match[2]) - 1, parseInt(match[3]));
    }
  } catch {}
  return new Date();
};

const parseLogDate = (timestampStr: string): Date => {
  try {
    // [2026-02-02 14:23:45:123] -> ISO format (replace last colon with dot for ms)
    const cleanTs = timestampStr.replace(/:(\d{3})$/, '.$1').replace(' ', 'T');
    return new Date(cleanTs);
  } catch {
    return new Date();
  }
};

const determineCategory = (message: string): LogCategory => {
  const msgUpper = message.toUpperCase();
  if (msgUpper.includes('FAIL') || msgUpper.includes('ERROR') || msgUpper.includes('EXCEPTION') || msgUpper.includes('UNABLE TO CONNECT')) return LogCategory.ERROR;
  if (msgUpper.includes('7DF') || msgUpper.includes('7E8') || msgUpper.includes('010D') || msgUpper.includes('STANDARD,')) return LogCategory.OBD;
  if (msgUpper.includes('BLE') || msgUpper.includes('CONNECT') || msgUpper.includes('INIT') || msgUpper.includes('SCAN')) return LogCategory.BLUETOOTH;
  if (msgUpper.includes('SCREEN') || msgUpper.includes('ONRESUME') || msgUpper.includes('ONSTOP')) return LogCategory.UI;
  return LogCategory.INFO;
};

export const parseLogFile = (content: string, fileName: string, billingContent: string = ''): ParsedData => {
  const lines = content.split(/\r?\n/);
  const logs: LogEntry[] = [];
  const lifecycleEvents: LifecycleEvent[] = [];
  const obdSeries: any[] = [];

  const metadata: SessionMetadata = {
    fileName, model: '알 수 없음', userOS: '알 수 없음', appVersion: '알 수 없음', carName: '알 수 없음', userId: '알 수 없음',
    logCount: 0, startTime: null, endTime: null, userInfo: {}, carInfo: {}, settingInfo: {}, appInfo: {}, extraInfo: {}
  };

  let currentSection = 'EXTRA';

  lines.forEach((line, idx) => {
    const trimmed = line.trim();
    if (!trimmed) return;

    // 1. 섹션 헤더 감지 (가이드 2번 항목)
    const sectionMatch = trimmed.match(SECTION_HEADER);
    if (sectionMatch) {
      const sectionName = sectionMatch[1].toUpperCase();
      if (sectionName.includes('DEVICE INFO')) currentSection = 'APP';
      else if (sectionName.includes('PROTOCOL INFO')) currentSection = 'EXTRA';
      else if (sectionName.includes('USER INFO')) currentSection = 'USER';
      else if (sectionName.includes('CAR INFO')) currentSection = 'CAR';
      else if (sectionName.includes('SETTING INFO')) currentSection = 'SETTING';
      else if (sectionName.includes('OBD2 INFO')) currentSection = 'EXTRA';
      return;
    }

    // 2. 키-값 쌍 파싱 (메타데이터 블록 내)
    const kvMatch = trimmed.match(KEY_VALUE_PAIR);
    if (kvMatch && !trimmed.startsWith('[')) {
      const k = kvMatch[1].trim();
      const v = kvMatch[2].trim();

      // 주요 필드 추출 및 한글화 매핑
      if (k === 'model') metadata.model = v;
      if (k === 'carName') metadata.carName = v;
      if (k === 'AT DPN') metadata.protocol = v;
      if (k === 'userKey' || k === 'userId') metadata.userId = v;
      if (k === 'userOS') metadata.userOS = v;
      if (k === 'version' || k === 'App version') metadata.appVersion = v;
      if (k === 'country') metadata.countryCode = v;

      switch (currentSection) {
        case 'USER': metadata.userInfo[k] = v; break;
        case 'CAR': metadata.carInfo[k] = v; break;
        case 'SETTING': metadata.settingInfo[k] = v; break;
        case 'APP': metadata.appInfo[k] = v; break;
        default: metadata.extraInfo[k] = v; break;
      }
      return;
    }

    // 3. 로그 포맷 파싱 (가이드 1번 항목)
    const logMatch = trimmed.match(REGEX_LOG_LINE);
    if (logMatch) {
      const timestampStr = logMatch[1];
      const message = logMatch[2].trim();
      const timestamp = parseLogDate(timestampStr);
      const category = determineCategory(message);

      const logEntry: LogEntry = {
        id: idx,
        timestamp,
        rawTimestamp: timestampStr,
        message,
        category,
        isError: category === LogCategory.ERROR,
        originalLine: trimmed
      };
      logs.push(logEntry);

      // OBD 데이터인 경우 시계열 데이터로 변환
      const obdPoint = parseObdLine(trimmed);
      if (obdPoint) obdSeries.push(obdPoint);

      // 라이프사이클 이벤트 추출
      if (category === LogCategory.BLUETOOTH || message.includes('Success') || message.includes('Close')) {
        lifecycleEvents.push({
          id: idx, timestamp, rawTimestamp: timestampStr, type: 'CONNECTION', message
        });
      } else if (category === LogCategory.UI || message.includes('MainActivity')) {
        lifecycleEvents.push({
          id: idx, timestamp, rawTimestamp: timestampStr, type: 'SCREEN', message
        });
      }
    }
  });

  metadata.logCount = logs.length;
  if (logs.length > 0) {
    metadata.startTime = logs[0].timestamp;
    metadata.endTime = logs[logs.length - 1].timestamp;
  }

  const metrics = aggregateMetrics(obdSeries);

  // 진단 요약
  let diagnosis: ConnectionDiagnosis = { status: 'SUCCESS', summary: '주행 세션이 정상적으로 확인되었습니다.', issues: [], csType: 'NONE' };
  if (content.includes('UNABLE TO CONNECT')) {
    diagnosis = { 
      status: 'FAILURE', 
      summary: '스캐너 연결 실패 (UNABLE TO CONNECT)', 
      issues: ['OBD2 스캐너와 앱 간의 블루투스 통신에 실패했습니다.'], 
      csType: 'GENERAL_CONNECTION' 
    };
  } else if (content.includes('NO DATA') || content.includes('NODATA')) {
    diagnosis = { 
      status: 'WARNING', 
      summary: '데이터 응답 없음 (NO DATA)', 
      issues: ['스캐너와 연결되었으나 차량 ECU에서 데이터를 응답하지 않습니다.'], 
      csType: 'NO_DATA_PROTOCOL' 
    };
  }

  return { metadata, logs, lifecycleEvents, billingLogs: [], diagnosis, fileList: [], obdSeries, metrics };
};

