const formatLabel = (key: string): string => KEY_LABELS[key] || key;

const CopyButton: React.FC<{ text: string }> = ({ text }) => {
  const [copied, setCopied] = useState(false);
  const handleCopy = () => {
    if (!text || text === '-') return;
    navigator.clipboard.writeText(text);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };
  return (
    <button 
      onClick={handleCopy} 
      className={`p-1 rounded transition-colors ${text && text !== '-' ? 'hover:bg-indigo-50 text-slate-400 hover:text-indigo-600' : 'opacity-0 cursor-default'}`}
    >
      {copied ? <Check className="w-3 h-3 text-green-500" /> : <Copy className="w-3 h-3" />}
    </button>
  );
};

const DetailCard: React.FC<{ title: string; icon: React.ReactNode; data: Record<string, string>; color: string }> = ({ title, icon, data, color }) => {
  const entries = Object.entries(data);
  if (entries.length === 0) return null;

  return (
    <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden flex flex-col">
      <div className={`px-5 py-3 border-b border-slate-100 flex items-center gap-2 font-bold text-sm ${color}`}>
        {icon}
        <h3>{title}</h3>
      </div>
      <div className="p-5 grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-x-8 gap-y-4">
        {entries.map(([key, value]) => (
          <div key={key} className="flex flex-col border-b border-slate-50 pb-2 last:border-0 last:pb-0">
            <div className="flex items-center justify-between mb-1">
              <span className="text-[10px] font-bold text-slate-400 uppercase tracking-tight">{formatLabel(key)}</span>
              <CopyButton text={value} />
            </div>
            <span className="text-sm text-slate-700 font-semibold truncate" title={value}>{value || '-'}</span>
          </div>
        ))}
      </div>
    </div>
  );
};

