              <div className="flex items-center gap-1.5">
                <div className="w-2 h-2 rounded-full bg-indigo-500" />
                <span className="text-xs font-medium text-slate-300">OBD 명령</span>
              </div>
              <span className="text-xs font-bold font-mono text-indigo-400">{payload[1].value}</span>
            </div>
            <div className="flex items-center justify-between gap-4">
              <div className="flex items-center gap-1.5">
