export const ObdDashboard: React.FC<ObdDashboardProps> = ({ series, metrics }) => {
  const [isPlaying, setIsPlaying] = useState(false);
  const [playbackSpeed, setPlaybackSpeed] = useState(1);
  const [currentTime, setCurrentTime] = useState(0); 
  const [selectedPids, setSelectedPids] = useState<Set<string>>(new Set(['0C', '0D']));

  // 분석 모드 설정
  const [activeSegmentId, setActiveSegmentId] = useState<number>(0); // 0: 전체
  const [isFollowMode, setIsFollowMode] = useState(true);
  const [viewWindowMs, setViewWindowMs] = useState(120000); // 2분 기본

  const requestRef = useRef<number>();
  const lastUpdateRef = useRef<number>();

  // 세션 분할
  const segments = useMemo(() => detectSegments(series), [series]);

  // 현재 활성화된 데이터 셋 (선택된 트립에 따라 필터링)
  const activeSeries = useMemo(() => {
    if (activeSegmentId === 0) return series;
    return segments.find(s => s.id === activeSegmentId)?.dataPoints || [];
  }, [activeSegmentId, series, segments]);

  const startTime = useMemo(() => activeSeries[0]?.unix || 0, [activeSeries]);
  const endTime = useMemo(() => activeSeries[activeSeries.length - 1]?.unix || 0, [activeSeries]);
  const totalDuration = useMemo(() => Math.max(0, endTime - startTime), [startTime, endTime]);

  // 세션 변경 시 재생 위치 초기화
  useEffect(() => {
    setCurrentTime(0);
    setIsPlaying(false);
  }, [activeSegmentId]);

  const animate = (time: number) => {
    if (lastUpdateRef.current !== undefined) {
      const deltaTime = time - lastUpdateRef.current;
      setCurrentTime(prev => {
        const next = prev + deltaTime * playbackSpeed;
        if (next >= totalDuration) {
          setIsPlaying(false);
          return totalDuration;
        }
        return next;
      });
    }
    lastUpdateRef.current = time;
    requestRef.current = requestAnimationFrame(animate);
  };

  useEffect(() => {
    if (isPlaying) {
      requestRef.current = requestAnimationFrame(animate);
    } else {
      lastUpdateRef.current = undefined;
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
    }
    return () => {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
    };
  }, [isPlaying, playbackSpeed, totalDuration]);

  // 재생 위치에 따른 현재 데이터 값
  const currentValues = useMemo(() => {
    const currentUnix = startTime + currentTime;
    // 성능을 위해 최근 데이터 포인트를 이진 탐색 등으로 찾는 것이 좋으나, 데이터 양이 보통 수천개 수준이므로 최적화된 루프 사용
    const latest: Record<string, number> = {};

    // 역순으로 탐색하여 현재 시간보다 작거나 같은 가장 최근 값을 찾음
    for (let i = activeSeries.length - 1; i >= 0; i--) {
      const p = activeSeries[i];
      if (p.unix <= currentUnix) {
        if (!latest[p.pid]) {
          latest[p.pid] = p.value;
        }
        // 모든 선택된 PID의 값이 채워지면 중단 가능하지만, 가독성을 위해 전체 순회
      }
    }
    return latest;
  }, [currentTime, activeSeries, startTime]);

  // 차트 데이터 가공 (선택된 세션 내에서만)
  const chartData = useMemo(() => {
    const dataBySec: Record<number, any> = {};

    activeSeries.forEach((p: ObdDataPoint) => {
      // 밀리초 단위를 초 단위로 내림하여 그룹화 (차트 밀도 조절)
      const sec = Math.floor((p.unix - startTime) / 1000) * 1000;
      if (!dataBySec[sec]) {
        dataBySec[sec] = { t: sec, timeLabel: formatSimTime(sec) };
      }
      dataBySec[sec][p.pid] = p.value;
    });

    const sorted = Object.values(dataBySec).sort((a: any, b: any) => a.t - b.t);

    if (!isFollowMode) return sorted;

    // Follow Mode: 현재 시간 기준으로 window 크기만큼만 보여줌
    // 현재 시간을 윈도우의 70% 지점에 위치시켜 앞부분 데이터를 더 많이 노출
    const offset = viewWindowMs * 0.7;
    const minT = Math.max(0, Math.min(currentTime - offset, totalDuration - viewWindowMs));
    const maxT = minT + viewWindowMs;

    return sorted.filter((d: any) => d.t >= minT && d.t <= maxT);
  }, [activeSeries, startTime, isFollowMode, currentTime, viewWindowMs, totalDuration]);

  const togglePid = (pid: string) => {
    setSelectedPids(prev => {
      const next = new Set(prev);
      if (next.has(pid)) next.delete(pid);
      else next.add(pid);
      return next;
    });
  };

  function formatSimTime(ms: number) {
    const totalSeconds = Math.floor(ms / 1000);
    const mins = Math.floor(totalSeconds / 60);
    const secs = totalSeconds % 60;
    return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
  }

  const getIcon = (pid: string) => {
    switch(pid) {
      case '0C': return <Activity className="w-5 h-5" />;
      case '0D': return <Zap className="w-5 h-5" />;
      case '05': return <Thermometer className="w-5 h-5" />;
      case '04': return <Gauge className="w-5 h-5" />;
      default: return <Wind className="w-5 h-5" />;
    }
  };

  const colors = ['#6366f1', '#f59e0b', '#ef4444', '#10b981', '#3b82f6', '#8b5cf6', '#ec4899', '#14b8a6'];

  return (
    <div className="space-y-6 pb-12 animate-in fade-in duration-500">
      {/* 1. 세션 선택 탭 */}
      <div className="flex items-center gap-2 overflow-x-auto pb-2 custom-scrollbar">
        <button
          onClick={() => setActiveSegmentId(0)}
          className={`flex items-center gap-2 px-4 py-2.5 rounded-xl text-sm font-bold whitespace-nowrap transition-all border-2 shadow-sm ${
            activeSegmentId === 0 ? 'bg-indigo-600 text-white border-indigo-600' : 'bg-white text-slate-600 border-slate-100 hover:border-indigo-200'
          }`}
        >
          <Map className="w-4 h-4" /> 전체 주행 기록
        </button>
        {segments.map(seg => (
          <button
            key={seg.id}
            onClick={() => setActiveSegmentId(seg.id)}
            className={`flex items-center gap-2 px-4 py-2.5 rounded-xl text-sm font-bold whitespace-nowrap transition-all border-2 shadow-sm ${
              activeSegmentId === seg.id ? 'bg-indigo-600 text-white border-indigo-600' : 'bg-white text-slate-600 border-slate-100 hover:border-indigo-200'
            }`}
          >
            <Calendar className="w-4 h-4" /> Trip {seg.id} ({seg.startLabel} ~ {seg.endLabel})
          </button>
        ))}
      </div>

      {/* 2. 재생 컨트롤러 */}
      <div className="bg-slate-900 p-5 md:p-6 rounded-3xl shadow-2xl border border-slate-800 flex flex-col md:flex-row items-center gap-6">
        <div className="flex items-center gap-3 shrink-0">
          <button 
            onClick={() => setIsPlaying(!isPlaying)}
            disabled={totalDuration <= 0}
            className={`w-14 h-14 flex items-center justify-center rounded-full transition-all shadow-lg ${
              isPlaying ? 'bg-rose-500 hover:bg-rose-400 shadow-rose-500/20' : 'bg-indigo-600 hover:bg-indigo-500 shadow-indigo-500/20'
            } disabled:opacity-50 disabled:cursor-not-allowed`}
          >
            {isPlaying ? <Pause className="w-7 h-7 fill-current" /> : <Play className="w-7 h-7 fill-current ml-1" />}
          </button>
          <button 
            onClick={() => { setIsPlaying(false); setCurrentTime(0); }}
            className="w-11 h-11 flex items-center justify-center bg-slate-800 hover:bg-slate-700 text-slate-300 rounded-full transition-all border border-slate-700"
          >
            <RotateCcw className="w-5 h-5" />
          </button>
        </div>

        <div className="flex-1 w-full space-y-3">
          <div className="flex justify-between text-[10px] font-black text-slate-500 uppercase tracking-widest px-1">
            <span className="flex items-center gap-1.5"><ClockIcon className="w-3 h-3" /> {formatSimTime(currentTime)}</span>
            <span>Total {formatSimTime(totalDuration)}</span>
          </div>
          <div className="relative group px-1">
            <input 
                type="range"
                min={0}
                max={totalDuration}
                value={currentTime}
                onChange={(e) => setCurrentTime(parseInt(e.target.value))}
                className="w-full h-2 bg-slate-800 rounded-full appearance-none cursor-pointer accent-indigo-500 transition-all group-hover:h-3"
            />
          </div>
        </div>

        <div className="flex items-center bg-slate-800 p-1.5 rounded-xl border border-slate-700 shrink-0">
          {[1, 4, 16, 64].map(speed => (
            <button
              key={speed}
              onClick={() => setPlaybackSpeed(speed)}
              className={`px-4 py-1.5 rounded-lg text-xs font-black transition-all ${playbackSpeed === speed ? 'bg-indigo-600 text-white shadow-sm' : 'text-slate-500 hover:text-slate-300'}`}
            >
              {speed}x
            </button>
          ))}
        </div>
      </div>

      {/* 3. 카드 뷰 그리드 */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        {(Object.values(metrics) as ObdMetric[]).map((m: ObdMetric) => (
          <MetricCard 
            key={m.id}
            name={m.name}
            value={currentValues[m.id] !== undefined ? currentValues[m.id] : '--'}
            unit={m.unit}
            isAvailable={m.isAvailable}
            isSelected={selectedPids.has(m.id)}
            icon={getIcon(m.id)}
            onClick={() => togglePid(m.id)}
          />
        ))}
      </div>

      {/* 4. 차트 분석 영역 */}
      <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm overflow-hidden transition-all hover:shadow-md">
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 mb-8">
          <div className="flex items-center gap-4">
            <div className="flex flex-col">
                <h3 className="font-black text-slate-900 flex items-center gap-2 mb-1">
                <Activity className="w-5 h-5 text-indigo-600" /> 주행 데이터 분석 리포트
                </h3>
                <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">
                    {activeSegmentId === 0 ? '전체 주행 데이터 분석 중' : `TRIP ${activeSegmentId} 집중 분석 중`}
                </span>
            </div>
            <div className="h-8 w-px bg-slate-100 hidden md:block" />
            <div className="flex items-center bg-slate-50 p-1 rounded-xl border border-slate-200">
               <button 
                onClick={() => setIsFollowMode(!isFollowMode)}
                className={`flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-xs font-black transition-all ${isFollowMode ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-400 hover:text-slate-600'}`}
               >
                 <Target className="w-3.5 h-3.5" /> 추적 모드
               </button>
               <div className="w-px h-4 bg-slate-200 mx-1.5" />
               <select 
                className="bg-transparent border-none text-[11px] font-black text-slate-500 focus:ring-0 outline-none cursor-pointer pr-8"
                value={viewWindowMs}
                onChange={(e) => setViewWindowMs(Number(e.target.value))}
               >
                 <option value={30000}>30초 뷰</option>
                 <option value={120000}>2분 뷰</option>
                 <option value={300000}>5분 뷰</option>
                 <option value={600000}>10분 뷰</option>
               </select>
            </div>
          </div>

          <div className="flex flex-wrap gap-2">
            {[...selectedPids].map((pid: string, idx: number) => (
              <div key={pid} className="flex items-center gap-2 px-3 py-1.5 bg-slate-50 border border-slate-200 rounded-lg text-[10px] font-black text-slate-600 shadow-sm transition-all hover:scale-105">
                <div className="w-2.5 h-2.5 rounded-full" style={{ backgroundColor: colors[idx % colors.length] }} />
                {metrics[pid]?.name}
              </div>
            ))}
          </div>
        </div>

        <div className="h-[480px] w-full">
          <ResponsiveContainer width="100%" height="100%">
            <LineChart data={chartData} margin={{ top: 10, right: 30, left: 10, bottom: 20 }}>
              <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
              <XAxis 
                dataKey="t" 
                fontSize={10} 
                tickFormatter={(val) => formatSimTime(val)} 
                axisLine={false} 
                tickLine={false}
                tick={{ fill: '#94a3b8', fontWeight: 600 }}
                dy={10}
              />
              <YAxis 
                fontSize={10} 
                axisLine={false} 
                tickLine={false}
                tick={{ fill: '#94a3b8', fontWeight: 600 }}
              />
              <Tooltip 
                labelFormatter={(val) => `경과 시간: ${formatSimTime(Number(val))}`}
                contentStyle={{ backgroundColor: 'rgba(15, 23, 42, 0.95)', border: 'none', borderRadius: '12px', boxShadow: '0 10px 25px -5px rgba(0,0,0,0.3)', color: '#fff', fontSize: '11px', padding: '12px' }}
                itemStyle={{ padding: '4px 0', fontWeight: 'bold' }}
                cursor={{ stroke: '#6366f1', strokeWidth: 1, strokeDasharray: '4 4' }}
              />
              <Legend verticalAlign="top" height={40} iconType="circle" wrapperStyle={{ fontSize: '11px', fontWeight: 'bold', textTransform: 'uppercase' }} />
              {[...selectedPids].map((pid: string, idx: number) => (
                <Line 
                  key={pid}
                  type="monotone" 
                  dataKey={pid} 
                  name={metrics[pid]?.name}
                  stroke={colors[idx % colors.length]} 
                  strokeWidth={3} 
                  dot={false} 
                  isAnimationActive={false}
                  connectNulls
                />
              ))}
              <ReferenceLine x={currentTime} stroke="#f43f5e" strokeWidth={2} strokeDasharray="5 5" label={{ position: 'top', value: '현재', fill: '#f43f5e', fontSize: 10, fontWeight: 'bold' }} />
            </LineChart>
          </ResponsiveContainer>
        </div>

        <div className="mt-6 p-4 bg-indigo-50/50 rounded-2xl flex items-center justify-between gap-4 border border-indigo-100">
          <div className="flex items-center gap-3">
            <div className="p-2 bg-indigo-100 rounded-lg text-indigo-600">
                <Eye className="w-4 h-4" />
            </div>
            <p className="text-[11px] text-indigo-800 font-bold leading-tight">
                {isFollowMode ? '현재 재생 위치를 자동으로 추적하여 차트를 이동시키고 있습니다.' : '차트 고정 모드입니다. 전체 흐름을 한눈에 확인할 수 있습니다.'}
            </p>
          </div>
          <div className="flex items-center gap-2 shrink-0">
            <span className="text-[10px] font-black text-indigo-300 uppercase tracking-tighter">Data Points</span>
            <span className="text-xs font-black text-indigo-600 tabular-nums">{activeSeries.length.toLocaleString()}</span>
          </div>
        </div>
      </div>
    </div>
  );
};

const ClockIcon = ({ className }: { className?: string }) => (
    <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round" className={className}>
        <circle cx="12" cy="12" r="10"/><polyline points="12 6 12 12 16 14"/>
    </svg>
);

import React, { useMemo, useState, useEffect, useRef } from 'react';
import { ObdDataPoint, ObdMetric } from '../types';
import { 
  LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, 
  ResponsiveContainer, Legend, ReferenceLine
} from 'recharts';
import { 
  Play, Pause, RotateCcw, Activity, Zap, Thermometer, 
  Gauge, Wind, Map, Eye, Target, Calendar, Clock, ArrowRight, BarChart3, Info
} from 'lucide-react';
import { detectSegments } from '../services/obdParser';

export interface ObdDashboardProps {
  series: ObdDataPoint[];
  metrics: Record<string, ObdMetric>;
}

const MetricCard: React.FC<any> = ({ name, value, unit, isAvailable, isSelected, icon, onClick }) => (
  <div 
    onClick={isAvailable ? onClick : undefined}
    className={`bg-white p-4 rounded-xl border-2 transition-all hover:shadow-md flex items-center justify-between group ${
      isSelected ? 'border-indigo-500 shadow-indigo-100 ring-2 ring-indigo-50' : 'border-slate-200'
    } ${isAvailable ? 'cursor-pointer' : 'opacity-40 grayscale cursor-not-allowed'}`}
  >
    <div className="flex items-center gap-4">
      <div className={`p-2.5 rounded-lg transition-colors ${isSelected ? 'bg-indigo-600 text-white' : 'bg-slate-50 text-slate-400 group-hover:bg-slate-100'}`}>
        {icon}
      </div>
      <div className="flex flex-col">
        <span className="text-[10px] font-bold text-slate-400 uppercase tracking-wider mb-0.5">{name}</span>
        <div className="flex items-baseline gap-1">
          <span className="text-xl font-black text-slate-800">{isAvailable ? value : '--'}</span>
          <span className="text-[10px] font-bold text-slate-400 uppercase">{unit}</span>
        </div>
      </div>
    </div>
  </div>
);

const TripStat: React.FC<{ label: string; value: string | number; unit: string; icon: React.ReactNode }> = ({ label, value, unit, icon }) => (
  <div className="flex items-center gap-3 px-4 py-2 bg-slate-50 rounded-lg border border-slate-100">
    <div className="text-slate-400">{icon}</div>
    <div className="flex flex-col">
      <span className="text-[9px] font-bold text-slate-400 uppercase tracking-tight">{label}</span>
      <div className="flex items-baseline gap-0.5">
        <span className="text-xs font-black text-slate-700">{value}</span>
        <span className="text-[8px] font-bold text-slate-400 uppercase">{unit}</span>
      </div>
    </div>
  </div>
);

export const ObdDashboard: React.FC<ObdDashboardProps> = ({ series, metrics }) => {
  const [isPlaying, setIsPlaying] = useState(false);
  const [playbackSpeed, setPlaybackSpeed] = useState(1);
  const [currentTime, setCurrentTime] = useState(0); 
  const [selectedPids, setSelectedPids] = useState<Set<string>>(new Set(['0C', '0D']));

  // 분석 모드 설정
  const [activeSegmentId, setActiveSegmentId] = useState<number>(0); // 0: 전체
  const [isFollowMode, setIsFollowMode] = useState(true);
  const [viewWindowMs, setViewWindowMs] = useState(120000); // 2분 기본

  const requestRef = useRef<number>();
  const lastUpdateRef = useRef<number>();

  // 세션 분할
  const segments = useMemo(() => detectSegments(series), [series]);

  // 현재 활성화된 데이터 셋 (선택된 트립에 따라 필터링)
  const activeSeries = useMemo(() => {
    if (activeSegmentId === 0) return series;
    return segments.find(s => s.id === activeSegmentId)?.dataPoints || [];
  }, [activeSegmentId, series, segments]);

  const startTime = useMemo(() => activeSeries[0]?.unix || 0, [activeSeries]);
  const endTime = useMemo(() => activeSeries[activeSeries.length - 1]?.unix || 0, [activeSeries]);
  const totalDuration = useMemo(() => Math.max(0, endTime - startTime), [startTime, endTime]);

  // 트립별 통계 계산
  const tripStats = useMemo(() => {
    const stats = {
      maxSpeed: 0,
      avgRpm: 0,
      maxRpm: 0,
      durationLabel: '',
      dataPoints: activeSeries.length
    };

    let rpmSum = 0;
    let rpmCount = 0;

    activeSeries.forEach(p => {
      if (p.pid === '0D') stats.maxSpeed = Math.max(stats.maxSpeed, p.value);
      if (p.pid === '0C') {
        stats.maxRpm = Math.max(stats.maxRpm, p.value);
        rpmSum += p.value;
        rpmCount++;
      }
    });

    stats.avgRpm = rpmCount > 0 ? Math.round(rpmSum / rpmCount) : 0;

    const d = totalDuration / 1000;
    const mins = Math.floor(d / 60);
    const secs = Math.floor(d % 60);
    stats.durationLabel = `${mins}분 ${secs}초`;

    return stats;
  }, [activeSeries, totalDuration]);

  // 세션 변경 시 재생 위치 초기화
  useEffect(() => {
    setCurrentTime(0);
    setIsPlaying(false);
  }, [activeSegmentId]);

  const animate = (time: number) => {
    if (lastUpdateRef.current !== undefined) {
      const deltaTime = time - lastUpdateRef.current;
      setCurrentTime(prev => {
        const next = prev + deltaTime * playbackSpeed;
        if (next >= totalDuration) {
          setIsPlaying(false);
          return totalDuration;
        }
        return next;
      });
    }
    lastUpdateRef.current = time;
    requestRef.current = requestAnimationFrame(animate);
  };

  useEffect(() => {
    if (isPlaying) {
      requestRef.current = requestAnimationFrame(animate);
    } else {
      lastUpdateRef.current = undefined;
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
    }
    return () => {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
    };
  }, [isPlaying, playbackSpeed, totalDuration]);

  // 재생 위치에 따른 현재 데이터 값
  const currentValues = useMemo(() => {
    const currentUnix = startTime + currentTime;
    const latest: Record<string, number> = {};

    for (let i = activeSeries.length - 1; i >= 0; i--) {
      const p = activeSeries[i];
      if (p.unix <= currentUnix) {
        if (!latest[p.pid]) {
          latest[p.pid] = p.value;
        }
      }
    }
    return latest;
  }, [currentTime, activeSeries, startTime]);

  const chartData = useMemo(() => {
    const dataBySec: Record<number, any> = {};

    activeSeries.forEach((p: ObdDataPoint) => {
      const sec = Math.floor((p.unix - startTime) / 1000) * 1000;
      if (!dataBySec[sec]) {
        dataBySec[sec] = { t: sec, timeLabel: formatSimTime(sec) };
      }
      dataBySec[sec][p.pid] = p.value;
    });

    const sorted = Object.values(dataBySec).sort((a: any, b: any) => a.t - b.t);

    if (!isFollowMode) return sorted;

    const offset = viewWindowMs * 0.7;
    const minT = Math.max(0, Math.min(currentTime - offset, totalDuration - viewWindowMs));
    const maxT = minT + viewWindowMs;

    return sorted.filter((d: any) => d.t >= minT && d.t <= maxT);
  }, [activeSeries, startTime, isFollowMode, currentTime, viewWindowMs, totalDuration]);

  const togglePid = (pid: string) => {
    setSelectedPids(prev => {
      const next = new Set(prev);
      if (next.has(pid)) next.delete(pid);
      else next.add(pid);
      return next;
    });
  };

  function formatSimTime(ms: number) {
    const totalSeconds = Math.floor(ms / 1000);
    const mins = Math.floor(totalSeconds / 60);
    const secs = totalSeconds % 60;
    return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
  }

  const getIcon = (pid: string) => {
    switch(pid) {
      case '0C': return <Activity className="w-5 h-5" />;
      case '0D': return <Zap className="w-5 h-5" />;
      case '05': return <Thermometer className="w-5 h-5" />;
      case '04': return <Gauge className="w-5 h-5" />;
      default: return <Wind className="w-5 h-5" />;
    }
  };

  const colors = ['#6366f1', '#f59e0b', '#ef4444', '#10b981', '#3b82f6', '#8b5cf6', '#ec4899', '#14b8a6'];

  return (
    <div className="space-y-6 pb-12 animate-in fade-in duration-500">

      {/* 1. 고도화된 세션 선택 섹션 */}
      <div className="space-y-3">
        <h3 className="text-xs font-black text-slate-400 uppercase tracking-widest flex items-center gap-2">
            <Calendar className="w-3.5 h-3.5" /> 주행 세션 목록 (Detected Trips)
        </h3>
        <div className="flex gap-4 overflow-x-auto pb-4 custom-scrollbar">
          {/* 전체 보기 카드 */}
          <div 
            onClick={() => setActiveSegmentId(0)}
            className={`min-w-[200px] p-4 rounded-2xl border-2 transition-all cursor-pointer flex flex-col justify-between group ${
                activeSegmentId === 0 ? 'bg-indigo-600 border-indigo-600 shadow-lg shadow-indigo-100' : 'bg-white border-slate-100 hover:border-indigo-200'
            }`}
          >
            <div className="flex items-center justify-between mb-2">
                <span className={`text-[10px] font-black uppercase tracking-widest ${activeSegmentId === 0 ? 'text-indigo-100' : 'text-slate-400'}`}>Overall</span>
                <Map className={`w-4 h-4 ${activeSegmentId === 0 ? 'text-white' : 'text-slate-300'}`} />
            </div>
            <p className={`text-lg font-black ${activeSegmentId === 0 ? 'text-white' : 'text-slate-800'}`}>전체 주행 기록</p>
            <div className={`mt-4 flex items-center gap-2 text-[10px] font-bold ${activeSegmentId === 0 ? 'text-indigo-200' : 'text-slate-400'}`}>
                <Activity className="w-3 h-3" /> {series.length.toLocaleString()} 데이터 포인트
            </div>
          </div>

          {/* 개별 트립 카드 */}
          {segments.map(seg => {
            const isSelected = activeSegmentId === seg.id;
            const duration = (seg.endTime - seg.startTime) / 1000;
            const mins = Math.floor(duration / 60);

            return (
                <div 
                    key={seg.id}
                    onClick={() => setActiveSegmentId(seg.id)}
                    className={`min-w-[240px] p-4 rounded-2xl border-2 transition-all cursor-pointer flex flex-col gap-3 group ${
                        isSelected ? 'bg-white border-indigo-500 shadow-lg shadow-indigo-50 ring-1 ring-indigo-100' : 'bg-white border-slate-100 hover:border-indigo-200'
                    }`}
                >
                    <div className="flex items-center justify-between">
                        <span className={`text-[10px] font-black uppercase tracking-widest ${isSelected ? 'text-indigo-600' : 'text-slate-400'}`}>Trip {seg.id}</span>
                        <div className={`px-2 py-0.5 rounded text-[10px] font-bold ${isSelected ? 'bg-indigo-100 text-indigo-700' : 'bg-slate-100 text-slate-500'}`}>
                            {mins}분 주행
                        </div>
                    </div>

                    <div className="flex items-center gap-3">
                        <div className="flex flex-col">
                            <span className="text-xs font-black text-slate-700">{seg.startLabel}</span>
                            <span className="text-[9px] font-bold text-slate-400">START</span>
                        </div>
                        <ArrowRight className="w-3 h-3 text-slate-300" />
                        <div className="flex flex-col">
                            <span className="text-xs font-black text-slate-700">{seg.endLabel}</span>
                            <span className="text-[9px] font-bold text-slate-400">END</span>
                        </div>
                    </div>

                    {isSelected && (
                        <div className="pt-2 border-t border-slate-50 flex items-center gap-2">
                            <div className="w-1.5 h-1.5 rounded-full bg-indigo-500 animate-pulse" />
                            <span className="text-[10px] font-bold text-indigo-600">현재 분석 중</span>
                        </div>
                    )}
                </div>
            );
          })}
        </div>
      </div>

      {/* 2. 트립 요약 통계 & 재생 컨트롤러 */}
      <div className="grid grid-cols-1 lg:grid-cols-12 gap-6">
        <div className="lg:col-span-8 bg-slate-900 p-6 rounded-3xl shadow-2xl border border-slate-800 flex flex-col md:flex-row items-center gap-6">
            <div className="flex items-center gap-3 shrink-0">
            <button 
                onClick={() => setIsPlaying(!isPlaying)}
                disabled={totalDuration <= 0}
                className={`w-14 h-14 flex items-center justify-center rounded-full transition-all shadow-lg ${
                isPlaying ? 'bg-rose-500 hover:bg-rose-400 shadow-rose-500/20' : 'bg-indigo-600 hover:bg-indigo-500 shadow-indigo-500/20'
                } disabled:opacity-50 disabled:cursor-not-allowed`}
            >
                {isPlaying ? <Pause className="w-7 h-7 fill-current" /> : <Play className="w-7 h-7 fill-current ml-1" />}
            </button>
            <button 
                onClick={() => { setIsPlaying(false); setCurrentTime(0); }}
                className="w-11 h-11 flex items-center justify-center bg-slate-800 hover:bg-slate-700 text-slate-300 rounded-full transition-all border border-slate-700"
            >
                <RotateCcw className="w-5 h-5" />
            </button>
            </div>

            <div className="flex-1 w-full space-y-3">
            <div className="flex justify-between text-[10px] font-black text-slate-500 uppercase tracking-widest px-1">
                <span className="flex items-center gap-1.5 text-indigo-400"><Clock className="w-3 h-3" /> {formatSimTime(currentTime)}</span>
                <span>Total {formatSimTime(totalDuration)}</span>
            </div>
            <div className="relative group px-1">
                <input 
                    type="range"
                    min={0}
                    max={totalDuration}
                    value={currentTime}
                    onChange={(e) => setCurrentTime(parseInt(e.target.value))}
                    className="w-full h-2 bg-slate-800 rounded-full appearance-none cursor-pointer accent-indigo-500 transition-all group-hover:h-3"
                />
            </div>
            </div>

            <div className="flex items-center bg-slate-800 p-1.5 rounded-xl border border-slate-700 shrink-0">
            {[1, 4, 16, 64].map(speed => (
                <button
                key={speed}
                onClick={() => setPlaybackSpeed(speed)}
                className={`px-4 py-1.5 rounded-lg text-xs font-black transition-all ${playbackSpeed === speed ? 'bg-indigo-600 text-white shadow-sm' : 'text-slate-500 hover:text-slate-300'}`}
                >
                {speed}x
                </button>
            ))}
            </div>
        </div>

        {/* 선택 세션 요약 위젯 */}
        <div className="lg:col-span-4 bg-white p-5 rounded-3xl border border-slate-200 shadow-sm flex flex-col justify-center gap-3">
            <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-1.5 mb-1">
                <BarChart3 className="w-3 h-3" /> Trip Summary
            </h4>
            <div className="grid grid-cols-2 gap-3">
                <TripStat label="최고 속도" value={tripStats.maxSpeed} unit="km/h" icon={<Zap className="w-3.5 h-3.5" />} />
                <TripStat label="평균 RPM" value={tripStats.avgRpm} unit="rpm" icon={<Activity className="w-3.5 h-3.5" />} />
