export enum LogCategory {
  OBD = 'OBD',
  BLUETOOTH = 'BLUETOOTH',
  PROTOCOL = 'PROTOCOL',
  ERROR = 'ERROR',
  UI = 'UI',
  INFO = 'INFO',
  GPS = 'GPS',
  BILLING = 'BILLING'
}

export interface LogEntry {
  id: number;
  timestamp: Date;
  rawTimestamp: string;
  category: LogCategory;
  isError: boolean;
  message: string;
  originalLine: string;
  memoryInfo?: string; // (사용MB/최대MB)
  isActivityVisible?: boolean;
}

export interface ObdDataPoint {
  timestamp: Date;
  timeStr: string;
  unix: number;
  pid: string;
  name: string;
  value: number;
  unit: string;
  delay: number;
  ecuHeader: string;
  pushType: string;
  mobdDataType?: string;
}

export interface ObdMetric {
  id: string;
  name: string;
  unit: string;
  currentValue: number;
  history: { t: number; v: number }[];
  isAvailable: boolean;
}

export interface LifecycleEvent {
  id: number;
  timestamp: Date;
  rawTimestamp: string;
  type: 'CONNECTION' | 'SCREEN' | 'PROTOCOL_SEARCH' | 'APP_STATE';
  message: string;
  details?: string;
  status?: 'START' | 'NEXT' | 'SUCCESS' | 'CANCEL' | 'FINISH';
}

export interface ConnectionDiagnosis {
  status: 'SUCCESS' | 'WARNING' | 'FAILURE' | 'UNKNOWN';
  summary: string;
  issues: string[];
  csType: 'GENERAL_CONNECTION' | 'NO_DATA_PROTOCOL' | 'WIFI_CONNECTION' | 'HUD_INTERFERENCE' | 'SUCCESS' | 'NONE';
}

export interface SessionMetadata {
  fileName: string;
  model: string;
  userOS: string;
  appVersion: string;
  carName: string;
  userId: string;
  protocol?: string;
  countryCode?: string;
  logCount: number;
  startTime: Date | null;
  endTime: Date | null;

  userInfo: Record<string, string>;
  carInfo: Record<string, string>;
  settingInfo: Record<string, string>;
  appInfo: Record<string, string>;
  extraInfo: Record<string, string>;
}

export interface ParsedData {
  metadata: SessionMetadata;
  logs: LogEntry[];
  lifecycleEvents: LifecycleEvent[];
  billingLogs: any[];
  diagnosis: ConnectionDiagnosis;
  fileList: { fileName: string; content: string }[];
  obdSeries: ObdDataPoint[];
