import { LogEntry, LogCategory, SessionMetadata, ParsedData, ConnectionDiagnosis, LifecycleEvent } from '../types';
import { parseObdLine, aggregateMetrics } from './obdParser';

// 가이드 5.1절 타임스탬프 정규식
const REGEX_LOG_LINE = /^\[(\d{4}-\d{2}-\d{2}\s\d{2}:\d{2}:\d{2}:\d{3})\]\/\/(.*)/;
const SECTION_HEADER = /^={3,}\s*(.*?)\s*={3,}/;
const KEY_VALUE_PAIR = /^([^:]+?)\s*:\s*(.*)/;

const parseLogDate = (ts: string): Date => {
  try {
    // [2026-02-02 14:23:45:123] -> 14:23:45.123 (JS Date는 마지막이 .이어야 함)
    const isoTs = ts.replace(' ', 'T').replace(/:(\d{3})$/, '.$1');
    return new Date(isoTs);
  } catch {
    return new Date();
  }
};

const determineCategory = (message: string): LogCategory => {
  const msg = message.toUpperCase();
  // 가이드 에러 응답 (2.8절)
  if (msg.includes('UNABLE TO CONNECT') || msg.includes('INIT FAIL') || msg.includes('ERROR') || msg.includes('EXCEPTION')) return LogCategory.ERROR;
  // 프로토콜 이모지 로그 (2.4절)
  if (/[🚀⏩✅⛔🚩👆🧹]/.test(message)) return LogCategory.PROTOCOL;
  // OBD 데이터 로그 (2.5절)
  if (msg.includes('DELAY :') && (msg.includes('STANDARD') || msg.includes('7DF') || /^[0-9A-F]{3},/.test(msg))) return LogCategory.OBD;
  // 블루투스 연결 (2.3절)
  if (msg.includes('BLUE') || msg.includes('INIT') || msg.includes('SCAN') || msg.includes('CONNECT')) return LogCategory.BLUETOOTH;
  // GPS 로그 (2.9절)
  if (msg.includes('GPS_PROTOCOL') || msg.includes('LOCATION')) return LogCategory.GPS;
  // UI 라이프사이클 (2.10절)
  if (msg.includes('MAINACTIVITY') || msg.includes('오버레이')) return LogCategory.UI;

  return LogCategory.INFO;
};

export const parseLogFile = (content: string, fileName: string): ParsedData => {
  const lines = content.split(/\r?\n/);
  const logs: LogEntry[] = [];
  const lifecycleEvents: LifecycleEvent[] = [];
  const obdSeries: any[] = [];

  const metadata: SessionMetadata = {
    fileName, model: '-', userOS: '-', appVersion: '-', carName: '-', userId: '-',
    logCount: 0, startTime: null, endTime: null, userInfo: {}, carInfo: {}, settingInfo: {}, appInfo: {}, extraInfo: {}
  };

  let currentSection = 'EXTRA';

  for (let i = 0; i < lines.length; i++) {
    const line = lines[i].trim();
    if (!line) continue;

    // 섹션 헤더 파싱 (가이드 2.1절)
    const sectionMatch = line.match(SECTION_HEADER);
    if (sectionMatch) {
      const name = sectionMatch[1].toUpperCase();
      if (name.includes('DEVICE')) currentSection = 'APP';
      else if (name.includes('PROTOCOL')) currentSection = 'EXTRA';
      else if (name.includes('USER')) currentSection = 'USER';
      else if (name.includes('CAR')) currentSection = 'CAR';
      else if (name.includes('SETTING')) currentSection = 'SETTING';
      continue;
    }

    // 키-값 파싱
    const kvMatch = line.match(KEY_VALUE_PAIR);
    if (kvMatch && !line.startsWith('[')) {
      const k = kvMatch[1].trim();
      const v = kvMatch[2].trim();

      if (k === 'model') metadata.model = v;
      if (k === 'carName') metadata.carName = v;
      if (k === 'AT DPN') metadata.protocol = v;
      if (k === 'userKey') metadata.userId = v;
      if (k === 'userOS') metadata.userOS = v;
      if (k === 'version') metadata.appVersion = v;
      if (k === 'country') metadata.countryCode = v;

      switch(currentSection) {
        case 'USER': metadata.userInfo[k] = v; break;
        case 'CAR': metadata.carInfo[k] = v; break;
        case 'SETTING': metadata.settingInfo[k] = v; break;
        case 'APP': metadata.appInfo[k] = v; break;
        default: metadata.extraInfo[k] = v; break;
      }
      continue;
    }

    // 로그 라인 파싱
    const logMatch = line.match(REGEX_LOG_LINE);
    if (logMatch) {
      const tsStr = logMatch[1];
      const msg = logMatch[2].trim();
      const timestamp = parseLogDate(tsStr);
      const category = determineCategory(msg);

      // 메모리 정보 추출 (가이드 2.5절 끝부분)
      const memMatch = msg.match(/\((.*)\)$/);
      const isActivityVisible = msg.includes('isActivityVisible : true');

      const entry: LogEntry = {
        id: i,
        timestamp,
        rawTimestamp: tsStr,
        message: msg,
        category,
        isError: category === LogCategory.ERROR,
        originalLine: line,
        memoryInfo: memMatch ? memMatch[1] : undefined,
        isActivityVisible
      };
      logs.push(entry);

      // OBD 파싱
      if (category === LogCategory.OBD) {
        const point = parseObdLine(line);
        if (point) obdSeries.push(point);
      }

      // 이벤트 추출
      if (category === LogCategory.PROTOCOL) {
        let status: LifecycleEvent['status'] = 'NEXT';
        if (msg.includes('시작')) status = 'START';
        else if (msg.includes('완료')) status = 'SUCCESS';
        else if (msg.includes('취소')) status = 'CANCEL';
        else if (msg.includes('종료')) status = 'FINISH';

        lifecycleEvents.push({
          id: i, timestamp, rawTimestamp: tsStr, type: 'PROTOCOL_SEARCH', message: msg, status
        });
      } else if (category === LogCategory.BLUETOOTH || msg.includes('connectionSuccess')) {
        lifecycleEvents.push({
          id: i, timestamp, rawTimestamp: tsStr, type: 'CONNECTION', message: msg
        });
      } else if (category === LogCategory.UI) {
        lifecycleEvents.push({
          id: i, timestamp, rawTimestamp: tsStr, type: 'SCREEN', message: msg
        });
      }
    } else if (logs.length > 0) {
      // 타임스탬프 없는 멀티라인 처리 (예외 스택트레이스)
      logs[logs.length - 1].message += '\n' + line;
    }
  }

  metadata.logCount = logs.length;
  if (logs.length > 0) {
    metadata.startTime = logs[0].timestamp;
    metadata.endTime = logs[logs.length - 1].timestamp;
  }

  const metrics = aggregateMetrics(obdSeries);

  // 룰 베이스 진단 (가이드 4.2~4.3절)
  let diagnosis: ConnectionDiagnosis = { status: 'SUCCESS', summary: '정상적인 주행 로그입니다.', issues: [], csType: 'NONE' };
  const contentUpper = content.toUpperCase();

  if (contentUpper.includes('UNABLE TO CONNECT')) {
    diagnosis = { status: 'FAILURE', summary: '연결 실패 (UNABLE TO CONNECT)', issues: ['OBD2 스캐너와의 초기 통신에 실패했습니다.'], csType: 'GENERAL_CONNECTION' };
  } else if (contentUpper.includes('NO DATA') || contentUpper.includes('NODATA')) {
    diagnosis = { status: 'WARNING', summary: '데이터 응답 없음 (NO DATA)', issues: ['차량 ECU에서 요청한 PID에 대한 데이터를 보내지 않습니다.'], csType: 'NO_DATA_PROTOCOL' };
  }

  return { metadata, logs, lifecycleEvents, billingLogs: [], diagnosis, fileList: [], obdSeries, metrics };
};

import { ObdDataPoint, ObdMetric } from '../types';

interface PidDefinition {
  name: string;
  unit: string;
  formula: (bytes: number[]) => number;
}

const PID_MAP: Record<string, PidDefinition> = {
  '04': { name: '엔진 부하', unit: '%', formula: (v) => (v[0] * 100) / 255 },
  '05': { name: '냉각수 온도', unit: '°C', formula: (v) => v[0] - 40 },
  '0C': { name: '엔진 회전수', unit: 'rpm', formula: (v) => (v[0] * 256 + v[1]) / 4 },
  '0D': { name: '주행 속도', unit: 'km/h', formula: (v) => v[0] },
  '0F': { name: '흡기 온도', unit: '°C', formula: (v) => v[0] - 40 },
  '11': { name: '스로틀 위치', unit: '%', formula: (v) => (v[0] * 100) / 255 },
  '42': { name: '제어 모듈 전압', unit: 'V', formula: (v) => (v[0] * 256 + v[1]) / 1000 },
};

/**
 * 가이드 2.5절 포맷: [ts]//{ECU}, {PID} : {RAW}, delay : {ms}, {PUSH_TYPE}
 */
const OBD_REGEX = /^\[(\d{4}-\d{2}-\d{2}\s\d{2}:\d{2}:\d{2}:\d{3})\]\/\/(.*?), ([0-9A-F]{4}) : (.*?), delay : (\d+)ms, (.*)/i;

export const parseObdLine = (line: string): ObdDataPoint | null => {
  const match = line.match(OBD_REGEX);
  if (!match) return null;

  const rawTs = match[1];
  const ecuHeader = match[2];
  const fullPid = match[3].toUpperCase();
  const rawData = match[4].replace(/\s/g, '').toUpperCase();
  const delay = parseInt(match[5]);
  const pushTypeInfo = match[6];

  const pid = fullPid.substring(2);
  const dataStartMarker = '41' + pid;
  const idx = rawData.indexOf(dataStartMarker);

  if (idx === -1 || rawData.includes('NODATA') || rawData.includes('ERROR')) return null;

  const dataHex = rawData.substring(idx + dataStartMarker.length);
  const bytes: number[] = [];
  for (let i = 0; i < dataHex.length; i += 2) {
    const b = parseInt(dataHex.substring(i, i + 2), 16);
    if (!isNaN(b)) bytes.push(b);
  }

  const def = PID_MAP[pid];
  if (!def || bytes.length === 0) return null;

  try {
    const timestamp = new Date(rawTs.replace(' ', 'T').replace(/:(\d{3})$/, '.$1'));
    const value = def.formula(bytes);

    return {
      timestamp,
      timeStr: rawTs.split(' ')[1],
      unix: timestamp.getTime(),
      pid,
      name: def.name,
      value: Number(value.toFixed(2)),
      unit: def.unit,
      delay,
      ecuHeader,
      pushType: pushTypeInfo.split('/')[0].trim()
    };
  } catch {
    return null;
  }
};

export const detectSegments = (series: ObdDataPoint[]) => {
  if (series.length === 0) return [];
  const GAP = 60000; // 1분 가이드 준수
  const segments = [];
  let current = [series[0]];

  for (let i = 1; i < series.length; i++) {
    if (series[i].unix - series[i-1].unix > GAP) {
      segments.push({
        id: segments.length + 1,
        startTime: current[0].unix,
        endTime: current[current.length - 1].unix,
        startLabel: current[0].timeStr,
        endLabel: current[current.length - 1].timeStr,
        dataPoints: current
      });
      current = [series[i]];
    } else {
      current.push(series[i]);
    }
  }
  segments.push({
    id: segments.length + 1,
    startTime: current[0].unix,
    endTime: current[current.length - 1].unix,
    startLabel: current[0].timeStr,
    endLabel: current[current.length - 1].timeStr,
    dataPoints: current
  });
  return segments;
};

export const aggregateMetrics = (series: ObdDataPoint[]): Record<string, ObdMetric> => {
  const metrics: Record<string, ObdMetric> = {};
  Object.keys(PID_MAP).forEach(id => {
    const s = series.filter(p => p.pid === id);
    metrics[id] = {
      id,
      name: PID_MAP[id].name,
      unit: PID_MAP[id].unit,
      currentValue: s.length > 0 ? s[s.length - 1].value : 0,
      history: s.map(p => ({ t: p.unix, v: p.value })),
      isAvailable: s.length > 0
    };
  });
  return metrics;
};

