import { GoogleGenAI } from "@google/genai";
import { ParsedData, LogCategory } from '../types';

export interface AiAnalysisResult {
  analysis: string;
  koreanResponse: string;
  translatedResponse: string | null;
  targetLanguage: string | null;
}

export const generateAiDiagnosis = async (data: ParsedData, userContext?: string, customApiKey?: string): Promise<AiAnalysisResult> => {
  const apiKey = customApiKey || process.env.API_KEY;
  if (!apiKey) throw new Error("API Key is missing.");

  const ai = new GoogleGenAI({ apiKey });
  const { metadata, logs, diagnosis, obdSeries } = data;

  // 지연 시간 통계 (가이드 4.3절)
  const avgDelay = obdSeries.length > 0 ? obdSeries.reduce((acc, p) => acc + p.delay, 0) / obdSeries.length : 0;
  const maxDelay = obdSeries.length > 0 ? Math.max(...obdSeries.map(p => p.delay)) : 0;

  const prompt = `
Act as a Senior Support Engineer for Infocar OBD2 Scanner.
Analyze the following log data according to the "Infocar Log Analysis Guide".

--- CONTEXT ---
- App Version: ${metadata.appVersion}
- Car: ${metadata.carName} (Fuel: ${metadata.carInfo['carFuelType']})
- Device: ${metadata.model} (${metadata.userOS})
- Target Language: ${metadata.countryCode || 'KR'}

--- TECHNICAL STATS ---
- Log Count: ${metadata.logCount}
- OBD Sampling Quality: Avg Delay ${avgDelay.toFixed(1)}ms, Max Delay ${maxDelay}ms
- Diagnosis Status: ${diagnosis.summary}
- Issues: ${diagnosis.issues.join(', ')}

--- TASKS (Based on Methodology 4.2-4.7) ---
1. Analyze connection quality: Look for delay spikes (>100ms) or 'UNABLE TO CONNECT'.
2. Check protocol negotiation: Did it reach '✅ 프로토콜 검색 완료'?
3. Provide a polite CS response in Korean. 
   - Start with "안녕하십니까 인포카입니다."
   - If Case 1 (General Connection) or Case 2 (No Data) from templates applies, use it.
   - Otherwise, provide a custom response based on logs.
4. Translate to local language if ${metadata.countryCode} is not KR.

Output strictly in JSON format.
{
  "analysis": "Technical reasoning",
  "koreanResponse": "CS template",
  "translatedResponse": "Translation or null",
  "targetLanguage": "Language Name"
}
`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: prompt,
      config: { responseMimeType: "application/json" }
    });
    return JSON.parse(response.text) as AiAnalysisResult;
  } catch (error) {
    console.error("AI Analysis Failed:", error);
    throw error;
  }
};

export enum LogCategory {
  OBD = 'OBD',
  BLUETOOTH = 'BLUETOOTH',
  PROTOCOL = 'PROTOCOL',
  ERROR = 'ERROR',
  UI = 'UI',
  INFO = 'INFO',
  GPS = 'GPS',
  BILLING = 'BILLING'
}

// LogFileContext to store file name and content for multiple files (e.g., from ZIP)
export interface LogFileContext {
  fileName: string;
  content: string;
}

export interface LogEntry {
  id: number;
  timestamp: Date;
  rawTimestamp: string;
  category: LogCategory;
  isError: boolean;
  message: string;
  originalLine: string;
  memoryInfo?: string; // (사용MB/최대MB)
  isActivityVisible?: boolean;
}

export interface ObdDataPoint {
  timestamp: Date;
  timeStr: string;
  unix: number;
  pid: string;
  name: string;
  value: number;
  unit: string;
  delay: number;
  ecuHeader: string;
  pushType: string;
  mobdDataType?: string;
}

export interface ObdMetric {
  id: string;
  name: string;
  unit: string;
  currentValue: number;
  history: { t: number; v: number }[];
  isAvailable: boolean;
}

export interface LifecycleEvent {
  id: number;
  timestamp: Date;
  rawTimestamp: string;
  type: 'CONNECTION' | 'SCREEN' | 'PROTOCOL_SEARCH' | 'APP_STATE';
  message: string;
  details?: string;
  status?: 'START' | 'NEXT' | 'SUCCESS' | 'CANCEL' | 'FINISH';
}

// CsDiagnosisType for unified template categorization in ConnectionStatus
export type CsDiagnosisType = 'GENERAL_CONNECTION' | 'NO_DATA_PROTOCOL' | 'WIFI_CONNECTION' | 'HUD_INTERFERENCE' | 'SUCCESS' | 'NONE';

export interface ConnectionDiagnosis {
  status: 'SUCCESS' | 'WARNING' | 'FAILURE' | 'UNKNOWN';
  summary: string;
  issues: string[];
  csType: CsDiagnosisType;
}

// BillingEntry for parsed billing and purchase transaction logs
export interface BillingEntry {
  id: number;
  timestamp: Date;
  rawTimestamp: string;
  os: 'ANDROID' | 'IOS';
  status: 'SUCCESS' | 'FAILURE';
  message: string;
  orderId?: string;
  productId?: string;
  productName?: string;
  price?: string;
  rawLog?: string;
}

export interface SessionMetadata {
  fileName: string;
  model: string;
  userOS: string;
  appVersion: string;
  carName: string;
  userId: string;
  protocol?: string;
  countryCode?: string;
  logCount: number;
  startTime: Date | null;
  endTime: Date | null;

  userInfo: Record<string, string>;
  carInfo: Record<string, string>;
  settingInfo: Record<string, string>;
  appInfo: Record<string, string>;
  extraInfo: Record<string, string>;
}

export interface ParsedData {
  metadata: SessionMetadata;
  logs: LogEntry[];
  lifecycleEvents: LifecycleEvent[];
  billingLogs: BillingEntry[];
  diagnosis: ConnectionDiagnosis;
  fileList: LogFileContext[];
  obdSeries: ObdDataPoint[];
  metrics: Record<string, ObdMetric>;
}

import { LogEntry, LogCategory, SessionMetadata, ParsedData, ConnectionDiagnosis, LifecycleEvent, BillingEntry } from '../types';
import { parseObdLine, aggregateMetrics } from './obdParser';

// 가이드 5.1절 타임스탬프 정규식
const REGEX_LOG_LINE = /^\[(\d{4}-\d{2}-\d{2}\s\d{2}:\d{2}:\d{2}:\d{3})\]\/\/(.*)/;
const SECTION_HEADER = /^={3,}\s*(.*?)\s*={3,}/;
const KEY_VALUE_PAIR = /^([^:]+?)\s* : \s*(.*)/;

const parseLogDate = (ts: string): Date => {
  try {
    // [2026-02-02 14:23:45:123] -> 14:23:45.123 (JS Date는 마지막이 .이어야 함)
    const isoTs = ts.replace(' ', 'T').replace(/:(\d{3})$/, '.$1');
    return new Date(isoTs);
  } catch {
    return new Date();
  }
};

const determineCategory = (message: string): LogCategory => {
  const msg = message.toUpperCase();
  // 가이드 에러 응답 (2.8절)
  if (msg.includes('UNABLE TO CONNECT') || msg.includes('INIT FAIL') || msg.includes('ERROR') || msg.includes('EXCEPTION')) return LogCategory.ERROR;
  // 프로토콜 이모지 로그 (2.4절)
  if (/[🚀⏩✅⛔🚩👆🧹]/.test(message)) return LogCategory.PROTOCOL;
  // OBD 데이터 로그 (2.5절)
  if (msg.includes('DELAY :') && (msg.includes('STANDARD') || msg.includes('7DF') || /^[0-9A-F]{3},/.test(msg))) return LogCategory.OBD;
  // 블루투스 연결 (2.3절)
  if (msg.includes('BLUE') || msg.includes('INIT') || msg.includes('SCAN') || msg.includes('CONNECT')) return LogCategory.BLUETOOTH;
  // GPS 로그 (2.9절)
  if (msg.includes('GPS_PROTOCOL') || msg.includes('LOCATION')) return LogCategory.GPS;
  // UI 라이프사이클 (2.10절)
  if (msg.includes('MAINACTIVITY') || msg.includes('오버레이')) return LogCategory.UI;

  return LogCategory.INFO;
};

// 결제 로그(Billing Content) 파싱 로직 추가
const parseBillingLogs = (content: string): BillingEntry[] => {
  if (!content) return [];
  const lines = content.split(/\r?\n/);
  const entries: BillingEntry[] = [];

  lines.forEach((line, idx) => {
    const trimmed = line.trim();
    if (!trimmed) return;

    // 단순 휴리스틱으로 상태 및 OS 판단
    const isError = trimmed.toUpperCase().includes('FAIL') || trimmed.toUpperCase().includes('ERROR') || trimmed.toUpperCase().includes('EXCEPTION');
    const os: 'ANDROID' | 'IOS' = (trimmed.toLowerCase().includes('purchase_log_') || trimmed.toLowerCase().includes('logfiles/')) ? 'IOS' : 'ANDROID';

    // 타임스탬프 추출 시도
    const tsMatch = trimmed.match(/^\[(\d{4}-\d{2}-\d{2}\s\d{2}:\d{2}:\d{2}:\d{3})\]/);
    const rawTimestamp = tsMatch ? tsMatch[1] : new Date().toISOString();
    const timestamp = tsMatch ? parseLogDate(tsMatch[1]) : new Date();

    // 주문 번호 및 상품 ID 추출 시도
    const orderMatch = trimmed.match(/orderId\s*[:=]\s*([^\s,]+)/i);
    const productMatch = trimmed.match(/productId\s*[:=]\s*([^\s,]+)/i);

    entries.push({
      id: idx,
      timestamp,
      rawTimestamp,
      os,
      status: isError ? 'FAILURE' : 'SUCCESS',
      message: trimmed.includes('//') ? trimmed.split('//')[1].trim() : trimmed,
      orderId: orderMatch ? orderMatch[1] : undefined,
      productId: productMatch ? productMatch[1] : undefined,
      rawLog: trimmed
    });
  });

  return entries;
};

export const parseLogFile = (content: string, fileName: string, billingContent?: string): ParsedData => {
  const lines = content.split(/\r?\n/);
  const logs: LogEntry[] = [];
  const lifecycleEvents: LifecycleEvent[] = [];
  const obdSeries: any[] = [];

  const metadata: SessionMetadata = {
    fileName, model: '-', userOS: '-', appVersion: '-', carName: '-', userId: '-',
    logCount: 0, startTime: null, endTime: null, userInfo: {}, carInfo: {}, settingInfo: {}, appInfo: {}, extraInfo: {}
  };

  let currentSection = 'EXTRA';

  for (let i = 0; i < lines.length; i++) {
    const line = lines[i].trim();
    if (!line) continue;

    // 섹션 헤더 파싱 (가이드 2.1절)
    const sectionMatch = line.match(SECTION_HEADER);
    if (sectionMatch) {
      const name = sectionMatch[1].toUpperCase();
      if (name.includes('DEVICE')) currentSection = 'APP';
      else if (name.includes('PROTOCOL')) currentSection = 'EXTRA';
      else if (name.includes('USER')) currentSection = 'USER';
      else if (name.includes('CAR')) currentSection = 'CAR';
      else if (name.includes('SETTING')) currentSection = 'SETTING';
      continue;
    }

    // 키-값 파싱
    const kvMatch = line.match(KEY_VALUE_PAIR);
    if (kvMatch && !line.startsWith('[')) {
      const k = kvMatch[1].trim();
      const v = kvMatch[2].trim();

      if (k === 'model') metadata.model = v;
      if (k === 'carName') metadata.carName = v;
      if (k === 'AT DPN') metadata.protocol = v;
      if (k === 'userKey') metadata.userId = v;
      if (k === 'userOS') metadata.userOS = v;
      if (k === 'version') metadata.appVersion = v;
      if (k === 'country') metadata.countryCode = v;

      switch(currentSection) {
        case 'USER': metadata.userInfo[k] = v; break;
        case 'CAR': metadata.carInfo[k] = v; break;
        case 'SETTING': metadata.settingInfo[k] = v; break;
        case 'APP': metadata.appInfo[k] = v; break;
        default: metadata.extraInfo[k] = v; break;
      }
      continue;
    }

    // 로그 라인 파싱
    const logMatch = line.match(REGEX_LOG_LINE);
    if (logMatch) {
      const tsStr = logMatch[1];
      const msg = logMatch[2].trim();
      const timestamp = parseLogDate(tsStr);
      const category = determineCategory(msg);

      // 메모리 정보 추출 (가이드 2.5절 끝부분)
      const memMatch = msg.match(/\((.*)\)$/);
      const isActivityVisible = msg.includes('isActivityVisible : true');

      const entry: LogEntry = {
        id: i,
        timestamp,
        rawTimestamp: tsStr,
        message: msg,
        category,
        isError: category === LogCategory.ERROR,
        originalLine: line,
        memoryInfo: memMatch ? memMatch[1] : undefined,
        isActivityVisible
      };
      logs.push(entry);

      // OBD 파싱
      if (category === LogCategory.OBD) {
        const point = parseObdLine(line);
        if (point) obdSeries.push(point);
      }

      // 이벤트 추출
      if (category === LogCategory.PROTOCOL) {
        let status: LifecycleEvent['status'] = 'NEXT';
        if (msg.includes('시작')) status = 'START';
        else if (msg.includes('완료')) status = 'SUCCESS';
        else if (msg.includes('취소')) status = 'CANCEL';
        else if (msg.includes('종료')) status = 'FINISH';

        lifecycleEvents.push({
          id: i, timestamp, rawTimestamp: tsStr, type: 'PROTOCOL_SEARCH', message: msg, status
        });
      } else if (category === LogCategory.BLUETOOTH || msg.includes('connectionSuccess')) {
        lifecycleEvents.push({
          id: i, timestamp, rawTimestamp: tsStr, type: 'CONNECTION', message: msg
        });
      } else if (category === LogCategory.UI) {
        lifecycleEvents.push({
          id: i, timestamp, rawTimestamp: tsStr, type: 'SCREEN', message: msg
        });
      }
    } else if (logs.length > 0) {
      // 타임스탬프 없는 멀티라인 처리 (예외 스택트레이스)
      logs[logs.length - 1].message += '\n' + line;
    }
  }

  metadata.logCount = logs.length;
  if (logs.length > 0) {
    metadata.startTime = logs[0].timestamp;
    metadata.endTime = logs[logs.length - 1].timestamp;
  }

  const metrics = aggregateMetrics(obdSeries);
  const billingLogs = parseBillingLogs(billingContent || '');

  // 룰 베이스 진단 (가이드 4.2~4.3절)
  let diagnosis: ConnectionDiagnosis = { status: 'SUCCESS', summary: '정상적인 주행 로그입니다.', issues: [], csType: 'NONE' };
  const contentUpper = content.toUpperCase();

  if (contentUpper.includes('UNABLE TO CONNECT')) {
    diagnosis = { status: 'FAILURE', summary: '연결 실패 (UNABLE TO CONNECT)', issues: ['OBD2 스캐너와의 초기 통신에 실패했습니다.'], csType: 'GENERAL_CONNECTION' };
  } else if (contentUpper.includes('NO DATA') || contentUpper.includes('NODATA')) {
    diagnosis = { status: 'WARNING', summary: '데이터 응답 없음 (NO DATA)', issues: ['차량 ECU에서 요청한 PID에 대한 데이터를 보내지 않습니다.'], csType: 'NO_DATA_PROTOCOL' };
  }

  return { metadata, logs, lifecycleEvents, billingLogs, diagnosis, fileList: [], obdSeries, metrics };
};

import { ObdDataPoint, ObdMetric, LogEntry } from '../types';

interface PidDefinition {
  name: string;
  unit: string;
  formula: (bytes: number[]) => number;
}

const PID_MAP: Record<string, PidDefinition> = {
  '04': { name: '엔진 부하', unit: '%', formula: (v) => (v[0] * 100) / 255 },
  '05': { name: '냉각수 온도', unit: '°C', formula: (v) => v[0] - 40 },
  '0C': { name: '엔진 회전수', unit: 'rpm', formula: (v) => (v[0] * 256 + v[1]) / 4 },
  '0D': { name: '주행 속도', unit: 'km/h', formula: (v) => v[0] },
  '0F': { name: '흡기 온도', unit: '°C', formula: (v) => v[0] - 40 },
  '11': { name: '스로틀 위치', unit: '%', formula: (v) => (v[0] * 100) / 255 },
  '2F': { name: '연료 잔량', unit: '%', formula: (v) => (v[0] * 100) / 255 },
  '42': { name: '배터리 전압', unit: 'V', formula: (v) => (v[0] * 256 + v[1]) / 1000 },
  '5C': { name: '오일 온도', unit: '°C', formula: (v) => v[0] - 40 },
};

/**
 * 가이드 2.5절 포맷 유연한 대응 정규식
 * [timestamp]//{ECU}, {PID} : {RAW}, delay : {ms}ms, {TYPE}
 */
const OBD_REGEX = /^\[(\d{4}-\d{2}-\d{2}\s\d{2}:\d{2}:\d{2}:\d{3})\]\/\/\s*(.*?),\s*([0-9A-F]{4})\s*:\s*(.*?),\s*delay\s*:\s*(\d+)ms,\s*(.*)/i;

export const parseObdLine = (line: string): ObdDataPoint | null => {
  const match = line.match(OBD_REGEX);
  if (!match) return null;

  const rawTs = match[1];
  const ecuHeader = match[2];
  const fullPid = match[3].toUpperCase();
  const rawData = match[4].replace(/\s/g, '').toUpperCase();
  const delay = parseInt(match[5]);
  const pushTypeInfo = match[6];

  // 010D -> 0D
  const pid = fullPid.length === 4 ? fullPid.substring(2) : fullPid;
  const def = PID_MAP[pid];
  if (!def) return null;

  // 에러 응답 필터링
  if (rawData.includes('NODATA') || rawData.includes('ERROR') || rawData.includes('STOPPED') || rawData === '?' || rawData === '') {
    return null;
  }

  // 데이터 시작 위치 찾기 (41 + PID)
  const dataStartMarker = '41' + pid;
  const idx = rawData.indexOf(dataStartMarker);

  // 만약 41XX가 없다면 (제조사 데이터 등), 전체 데이터 사용 시도 또는 무시
  let dataHex = '';
  if (idx !== -1) {
    dataHex = rawData.substring(idx + dataStartMarker.length);
  } else {
    // 표준 OBD 응답이 아닌 경우 (헤더 제외 로직)
    dataHex = rawData; 
  }

  const bytes: number[] = [];
  for (let i = 0; i < dataHex.length; i += 2) {
    const b = parseInt(dataHex.substring(i, i + 2), 16);
    if (!isNaN(b)) bytes.push(b);
  }

  if (bytes.length === 0) return null;

  try {
    const timestamp = new Date(rawTs.replace(' ', 'T').replace(/:(\d{3})$/, '.$1'));
    const value = def.formula(bytes);

    return {
      timestamp,
      timeStr: rawTs.split(' ')[1],
      unix: timestamp.getTime(),
      pid,
      name: def.name,
      value: Number(value.toFixed(2)),
      unit: def.unit,
      delay,
      ecuHeader,
      pushType: pushTypeInfo.split('/')[0].trim()
    };
  } catch {
    return null;
  }
};

/**
 * 주행 세션 분리 로직 고도화
 * 1. 'Log Started' 마커 기준 (물리적 재연결)
 * 2. 1분 이상의 시간 간격 기준 (휴지기)
 */
export const detectSegments = (series: ObdDataPoint[], allLogs: LogEntry[] = []) => {
  if (series.length === 0) return [];

  const GAP = 60000; 
  const segments = [];

  // 로그 마커에서 세션 시작 지점(Unix time) 추출
  const sessionStarts = allLogs
    .filter(l => l.message.includes('Log Started') || l.message.includes('Connect Success Data Log Started'))
    .map(l => l.timestamp.getTime());

  let current: ObdDataPoint[] = [];

  for (let i = 0; i < series.length; i++) {
    const point = series[i];
    const prevPoint = i > 0 ? series[i - 1] : null;

    // 세션 분리 조건:
    // 1. 현재 포인트 이전에 'Log Started' 마커가 있었는가?
    const isNewSessionMarker = sessionStarts.some(ts => prevPoint ? (ts > prevPoint.unix && ts <= point.unix) : ts <= point.unix);
    // 2. 시간 간격이 너무 큰가?
    const isTimeGap = prevPoint ? (point.unix - prevPoint.unix > GAP) : false;

    if ((isNewSessionMarker || isTimeGap) && current.length > 0) {
      segments.push({
        id: segments.length + 1,
        startTime: current[0].unix,
        endTime: current[current.length - 1].unix,
        startLabel: current[0].timeStr,
        endLabel: current[current.length - 1].timeStr,
        dataPoints: current
      });
      current = [point];
    } else {
      current.push(point);
    }
  }

  if (current.length > 0) {
    segments.push({
      id: segments.length + 1,
      startTime: current[0].unix,
      endTime: current[current.length - 1].unix,
      startLabel: current[0].timeStr,
      endLabel: current[current.length - 1].timeStr,
      dataPoints: current
    });
  }

  return segments;
};

export const aggregateMetrics = (series: ObdDataPoint[]): Record<string, ObdMetric> => {
  const metrics: Record<string, ObdMetric> = {};
  Object.keys(PID_MAP).forEach(id => {
    const s = series.filter(p => p.pid === id);
    metrics[id] = {
      id,
      name: PID_MAP[id].name,
      unit: PID_MAP[id].unit,
      currentValue: s.length > 0 ? s[s.length - 1].value : 0,
      history: s.map(p => ({ t: p.unix, v: p.value })),
      isAvailable: s.length > 0
    };
  });
  return metrics;
};

import React, { useMemo, useState, useEffect, useRef } from 'react';
import { ObdDataPoint, ObdMetric, LogEntry } from '../types';
import { 
  LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, 
  ResponsiveContainer, Legend, ReferenceLine
} from 'recharts';
import { 
  Play, Pause, RotateCcw, Activity, Zap, Thermometer, 
  Gauge, Wind, Map, Eye, Target, Calendar, Clock, ArrowRight, BarChart3, Info
} from 'lucide-react';
import { detectSegments } from '../services/obdParser';

export interface ObdDashboardProps {
  series: ObdDataPoint[];
  metrics: Record<string, ObdMetric>;
  allLogs?: LogEntry[]; // 세션 분리 정밀도를 위해 전체 로그 추가
}

