        <div className="flex-1">
          <h1 className="text-2xl font-bold text-slate-900 flex items-center gap-2 mb-2">
            <span className="bg-indigo-600 text-white p-1 rounded text-lg">INF</span> Infocar 로그 분석기
          </h1>

          <div className="flex items-center gap-3">
             <div className="relative group">
                <div className="flex items-center gap-2 bg-slate-100 hover:bg-slate-200 transition-colors px-3 py-1.5 rounded-md cursor-pointer border border-slate-200 shadow-sm">
                    <FileText className="w-4 h-4 text-slate-600" />
                    <select 
                        className="bg-transparent border-none text-sm font-bold text-slate-700 focus:ring-0 cursor-pointer appearance-none pr-8 outline-none"
                        value={metadata.fileName}
                        onChange={(e) => onFileSelect(e.target.value)}
